def find_Rotations(s):
    n = len(s)
    for i in range(1, n):
        if s[i:] + s[:i] == s:
            return i
    return n

import re

def text_lowercase_underscore(text):
    pattern = r'^[a-z]+_[a-z]+$'
    if re.match(pattern, text):
        return 'Found a match!'
    else:
        return 'Not matched!'

def str_to_list(s):
    return list(s)

def remove_dirty_chars(str1, str2):
    str1_list = str_to_list(str1)
    str2_set = set(str2)

    result = [char for char in str1_list if char not in str2_set]

    return ''.join(result)
